mapper.select:
SELECT
    id, line_no, data_source_name, data_source_no, data_category_no, source_from, source_type, field, type, format, version, is_valid, create_at
FROM data_source


        line_no = #{param.lineNo}


        AND data_source_name like CONCAT(#{param.dataSourceName}, '%')


        AND data_source_no = #{param.dataSourceNo}


        AND data_category_no = #{param.dataCategoryNo}


        AND field = #{param.field}


        AND is_valid = #{param.isValid}

    AND is_delete = 0

LIMIT #{start}, #{limit}

SELECT COUNT(*)
FROM data_source


        line_no = #{param.lineNo}


        AND data_source_name like CONCAT(#{param.dataSourceName}, '%')


        AND data_source_no = #{param.dataSourceNo}


        AND data_category_no = #{param.dataCategoryNo}


        AND field = #{param.field}


        AND is_valid = #{param.isValid}

    AND is_delete = 0

SELECT data_source_no as no, data_source_name as name, data_category_no, field, type, format, version, is_valid FROM data_source WHERE data_source_no IN
#{no}
AND is_delete = 0
